def get_Position(arr, target):
    for i, element in enumerate(arr):
        if element == target:
            return i

# Test cases
assert get_Position([2,5,4],3) == -1
assert get_Position([4,3],2,2) == 2
assert get_Position([1,2,3,4],4,1) == 4

def get_last_occurrence(arr, target):
    for i in range(len(arr)-1, -1, -1):
        if arr[i] == target:
            return i

# Test cases
assert get_last_occurrence([2,5,4], 3) == -1
assert get_last_occurrence([4,3], 2) == 2
assert get_last_occurrence([1,2,3,4], 4) == 4
